    result: Result<i32, cudarc::driver::DriverError>,
) -> Result<i32, CudaError> {
    match result {
        Ok(count) => Ok(count),
        Err(cudarc::driver::DriverError(cudarc::driver::sys::CUresult::CUDA_ERROR_NO_DEVICE)) => {
            Err(CudaError::NoDevice)
