        let inputs = self
            .stream
            .memcpy_dtov(&self.inputs)
            .map_err(driver_error)?;
        let input_counts = self
            .stream
            .memcpy_dtov(&self.input_counts)
            .map_err(driver_error)?;
        Ok(hash_state(
            &self.model,
            &self.layout,
            &state,
            &inputs,
            &input_counts,
