                    writeln!(out, "  for (unsigned int part = 0; part < 2U; ++part) {{ unsigned long long begin = part == 0U ? 0ULL : midpoint; unsigned long long end = part == 0U ? midpoint : input_counts[{port}]; for (unsigned long long row = begin; row < end; ++row) {{").unwrap();
                    let selected = if let Some(filter) = &spec.agg.filter {
