    times: CudaSlice<f64>,
    candidate_errors: CudaSlice<u8>,
    wins: CudaSlice<u8>,
    write_offsets: CudaSlice<u64>,
    owners: CudaSlice<i32>,
    owner_values: CudaSlice<u64>,
    output_partials: CudaSlice<u64>,
    output_errors: CudaSlice<u8>,
