 835	fn build_output(
 836	    model: &ValidatedModel,
 837	    snapshot: &Snapshot<'_>,
 838	    params: &ParamEnv,
 839	    model_box: &sembla_ir::Box,
 840	    output: &sembla_ir::OutputDecl,
 841	) -> Result<InputTable, TickError> {
 842	    let OutputBuilder::PerTable { table, fields } = &output.builder;
 843	    let eval_table = EvalTable::new(model, &model_box.name, table)?;
 844	    let rows = snapshot.row_count(&model_box.name, table)?;
 845	    let mut cache = AggCache::new(model, snapshot, params);
 846	    let mut columns = Vec::with_capacity(fields.len());
 847	    for field in fields {
 848	        let selected = match &field.filter {
 849	            Some(filter) => match eval_column(filter, eval_table, snapshot, params, &mut cache)? {
 850	                ValueColumn::Bool(values) => values,
 851	                other => return Err(runtime_type("output filter", &other)),
 852	            },
 853	            None => vec![true; rows],
 854	        };
 855	        let column = match &field.op {
 856	            AggOp::Count => {
 857	                let count = selected.iter().filter(|value| **value).count();
 858	                ColumnData::Int(vec![i64::try_from(count).map_err(|_| {
 859	                    TickError::Evaluation("output count exceeds i64".to_owned())
 860	                })?])
 861	            }
